      { "from": "Order Saga Orchestrator", "to": "Inventory Service", "contract": "reserveItems(sagaId, orderId, items[]) → { reservationId } | releaseReservation(sagaId, reservationId) → { status: RELEASED }", "coupling_type": "command — synchronous or async command/reply" },
