      { "from": "Order Saga Orchestrator", "to": "Courier Service", "contract": "assignCourier(sagaId, orderId, pickupLocation, deliveryLocation) → { courierId, assignmentId } | unassignCourier(sagaId, assignmentId) → { status: UNASSIGNED }", "coupling_type": "command — synchronous or async command/reply" },
      { "from": "Order Saga Orchestrator", "to": "Saga State Store", "contract": "saveSagaState(sagaId, stepIndex, status, compensationLog) | loadSagaState(sagaId) → SagaInstance", "coupling_type": "data — direct persistence" }
