      { "name": "Courier Assignment", "classification": "core", "aggregates": ["CourierAssignment (root: assignmentId, states: ASSIGNED → UNASSIGNED → COMPLETED)", "Courier (root: courierId, availability state)"] },
      { "name": "Saga Coordination", "classification": "supporting", "aggregates": ["SagaInstance (root: sagaId, contains: stepResults[], compensationLog[], currentState)"] }
